19	    /**
20	     * GET /api/v1/recipes
21	     *
22	     * List recipes with pagination.
23	     */
24	    public function index(RecipeService $recipeService): Response
25	    {
26	        $filters = [
27	            'status'   => $this->request->get('status'),
28	            'category' => $this->request->get('category'),
29	            'page'     => (int) $this->request->get('page', 1),
30	            'per_page' => (int) $this->request->get('per_page', 20),
31	        ];
32	
33	        $page    = max(1, $filters['page']);
34	        $perPage = min(100, max(1, $filters['per_page']));
35	
36	        $query = Recipe::order('created_at', 'desc');
37	        $this->applySiteScope($query);
38	
39	        if (!empty($filters['status'])) {
40	            $query->where('status', $filters['status']);
41	        }
42	        if (!empty($filters['category'])) {
43	            $query->where('category', $filters['category']);
44	        }
45	
46	        $total      = $query->count();
47	        $totalPages = (int) ceil($total / $perPage);
48	        $items      = $query->page($page, $perPage)
49	                            ->select()
50	                            ->toArray();
51	
52	        return $this->success([
53	            'items'      => $items,
54	            'pagination' => [
55	                'page'        => $page,
56	                'per_page'    => $perPage,
57	                'total'       => $total,
58	                'total_pages' => $totalPages,
59	            ],
60	        ]);
61	    }
