63	    /**
64	     * POST /api/v1/recipes
65	     *
66	     * Create a new recipe.
67	     */
68	    public function create(RecipeService $recipeService): Response
69	    {
70	        $input = json_decode($this->request->getInput(), true) ?: [];
71	
72	        try {
73	            validate(RecipeValidate::class)->scene('create')->check($input);
74	        } catch (ValidateException $e) {
75	            return $this->error('VALIDATION_FAILED', $e->getMessage(), [], 422);
76	        }
77	
78	        $siteId = (int) $input['site_id'];
79	        if (!$this->canAccessSite($siteId)) {
80	            return $this->error('FORBIDDEN_SITE_SCOPE', 'You do not have access to this site.', [], 403);
81	        }
82	
83	        $data = $recipeService->create([
84	            'title'      => $input['title'],
85	            'site_id'    => $siteId,
86	            'status'     => 'draft',
87	            'created_by' => $this->request->userId,
88	        ], $this->request->userId);
89	
90	        return $this->success([
91	            'id'      => $data['id'] ?? null,
92	            'message' => 'Recipe created.',
93	        ], 201);
94	    }
