96	    /**
97	     * GET /api/v1/recipes/:id
98	     *
99	     * Read a single recipe.
100	     */
101	    public function read($id, RecipeService $recipeService): Response
102	    {
103	        $recipe = $recipeService->find((int) $id, $this->request->siteScopes);
104	
105	        if (!$recipe) {
106	            return $this->error('NOT_FOUND', 'Recipe not found.', [], 404);
107	        }
108	
109	        $versions = RecipeVersion::where('recipe_id', (int) $id)
110	            ->order('version_number', 'desc')
111	            ->select()
112	            ->toArray();
113	
114	        // Extract ingredients from content_json for stable frontend rehydration
115	        foreach ($versions as &$ver) {
116	            $contentData = !empty($ver['content_json']) ? json_decode($ver['content_json'], true) : null;
117	            $ver['ingredients'] = (is_array($contentData) && isset($contentData['ingredients']))
118	                ? $contentData['ingredients']
119	                : [];
120	        }
121	        unset($ver);
122	
123	        $recipe['versions'] = $versions;
124	
125	        return $this->success($recipe);
126	    }
