152	    /**
153	     * PUT /api/v1/recipe-versions/:id
154	     *
155	     * Update a draft version. $id is the VERSION id from the route.
156	     */
157	    public function updateVersion($id, RecipeService $recipeService): Response
158	    {
159	        $version = RecipeVersion::where('id', (int) $id)->find();
160	
161	        if (!$version) {
162	            return $this->error('NOT_FOUND', 'Version not found.', [], 404);
163	        }
164	
165	        // Site scope check via the parent recipe
166	        $recipe = $recipeService->find((int) $version->recipe_id, $this->request->siteScopes);
167	        if (!$recipe) {
168	            return $this->error('NOT_FOUND', 'Recipe not found.', [], 404);
169	        }
170	
171	        $input = json_decode($this->request->getInput(), true) ?: [];
172	
173	        try {
174	            validate(RecipeVersionValidate::class)->check($input);
175	        } catch (ValidateException $e) {
176	            return $this->error('VALIDATION_FAILED', $e->getMessage(), [], 422);
177	        }
178	
179	        // Validate ingredients if provided
180	        if (!empty($input['ingredients']) && is_array($input['ingredients'])) {
181	            $ingredientError = \app\validate\RecipeVersionValidate::validateIngredients($input['ingredients']);
182	            if ($ingredientError) {
183	                return $this->error('VALIDATION_FAILED', $ingredientError, [], 422);
184	            }
185	        }
186	
187	        if ($version->status !== 'draft') {
188	            return $this->error('WORKFLOW_CONFLICT', 'Only draft versions can be updated.', [], 409);
189	        }
190	
191	        // Update steps as structured data in recipe_steps table
192	        if (!empty($input['steps']) && is_array($input['steps'])) {
193	            \think\facade\Db::name('recipe_steps')->where('version_id', (int)$id)->delete();
194	            foreach ($input['steps'] as $i => $step) {
195	                \think\facade\Db::name('recipe_steps')->insert([
196	                    'version_id' => (int)$id,
197	                    'step_number' => $i + 1,
198	                    'instruction' => $step['instruction'] ?? '',
199	                    'duration_minutes' => $step['duration_minutes'] ?? null,
200	                    'created_at' => date('Y-m-d H:i:s'),
201	                ]);
202	            }
203	        }
204	
205	        // Persist ingredients into content_json as structured data
206	        $contentData = [];
207	        $existingContent = $version->content_json ? json_decode($version->content_json, true) : null;
208	        if (is_array($existingContent)) {
209	            $contentData = $existingContent;
210	        } elseif ($version->content_json) {
211	            $contentData = ['body' => $version->content_json];
212	        }
213	
214	        if (isset($input['content_json'])) {
215	            $decoded = json_decode($input['content_json'], true);
216	            if (is_array($decoded)) {
217	                $contentData = array_merge($contentData, $decoded);
218	            } else {
219	                $contentData['body'] = $input['content_json'];
220	            }
221	        }
222	
223	        if (!empty($input['ingredients']) && is_array($input['ingredients'])) {
224	            $contentData['ingredients'] = $input['ingredients'];
225	        }
226	
227	        $version->save([
228	            'content_json' => json_encode($contentData),
229	            'total_time'   => $input['total_time'] ?? $version->total_time,
230	            'difficulty'   => $input['difficulty'] ?? $version->difficulty,
231	            'prep_time'    => $input['prep_time'] ?? $version->prep_time,
232	            'cook_time'    => $input['cook_time'] ?? $version->cook_time,
233	        ]);
234	
235	        return $this->success([
236	            'version_id' => (int) $id,
237	            'message'    => 'Version updated.',
238	        ]);
239	    }
