277	    /**
278	     * GET /api/v1/recipe-versions/:id/diff
279	     *
280	     * Show the diff between this version and the previous version.
281	     * $id is the VERSION id from the route.
282	     */
283	    public function diff($id, RecipeService $recipeService): Response
284	    {
285	        $version = RecipeVersion::where('id', (int) $id)->find();
286	
287	        if (!$version) {
288	            return $this->error('NOT_FOUND', 'Version not found.', [], 404);
289	        }
290	
291	        // Site scope check via the parent recipe
292	        $recipe = $recipeService->find((int) $version->recipe_id, $this->request->siteScopes);
293	        if (!$recipe) {
294	            return $this->error('NOT_FOUND', 'Recipe not found.', [], 404);
295	        }
296	
297	        $current = $version->toArray();
298	
299	        // Get the previous version of the same recipe
300	        $previous = RecipeVersion::where('recipe_id', (int) $version->recipe_id)
301	            ->where('version_number', '<', $version->version_number)
302	            ->order('version_number', 'desc')
303	            ->find();
304	
305	        if (!$previous) {
306	            return $this->success([
307	                'version_id' => (int) $id,
308	                'changes'    => [],
309	                'message'    => 'No previous version to compare.',
310	            ]);
311	        }
312	
313	        $previousData = $previous->toArray();
314	        $changes      = [];
315	
316	        $currentContent  = json_decode($current['content_json'] ?? '[]', true) ?: [];
317	        $previousContent = json_decode($previousData['content_json'] ?? '[]', true) ?: [];
318	
319	        foreach (['total_time', 'difficulty', 'prep_time', 'cook_time'] as $field) {
320	            if (($current[$field] ?? null) !== ($previousData[$field] ?? null)) {
321	                $changes[] = [
322	                    'field' => $field,
323	                    'old'   => $previousData[$field] ?? null,
324	                    'new'   => $current[$field] ?? null,
325	                ];
326	            }
327	        }
328	
329	        if ($currentContent !== $previousContent) {
330	            $changes[] = [
331	                'field' => 'steps',
332	                'old'   => $previousContent,
333	                'new'   => $currentContent,
334	            ];
335	        }
336	
337	        return $this->success([
338	            'version_id'       => (int) $id,
339	            'current_version'  => $current['version_number'],
340	            'previous_version' => $previousData['version_number'],
341	            'changes'          => $changes,
342	        ]);
343	    }
