17	class ReportController extends BaseController
18	{
19	    /**
20	     * GET /api/v1/reports/definitions
21	     */
22	    private const REPORT_ROLES = ['operations_analyst', 'finance_clerk', 'administrator', 'auditor'];
23	
24	    public function listDefinitions(ReportService $reportService): Response
25	    {
26	        $userRoles = $this->request->roles ?? [];
27	        if (empty(array_intersect($userRoles, self::REPORT_ROLES))) {
28	            return $this->error('FORBIDDEN_ROLE', 'Report access requires analyst, finance, admin, or auditor role.', [], 403);
29	        }
30	        $privilegedRoles = ['administrator', 'auditor'];
31	
32	        $query = \think\facade\Db::name('report_definitions')
33	            ->order('id', 'desc');
34	
35	        // Non-privileged users can only see their own definitions
36	        if (empty(array_intersect($userRoles, $privilegedRoles))) {
37	            $query->where('created_by', $this->request->userId);
38	        }
39	
40	        $items = $query->select()->toArray();
41	
42	        // Decode JSON fields for frontend consistency
43	        foreach ($items as &$item) {
44	            $item['dimensions'] = !empty($item['dimensions_json']) ? json_decode($item['dimensions_json'], true) : [];
45	            $item['filters'] = !empty($item['filters_json']) ? json_decode($item['filters_json'], true) : [];
46	            $item['columns'] = !empty($item['columns_json']) ? json_decode($item['columns_json'], true) : [];
47	        }
48	        unset($item);
49	
50	        return $this->success(['items' => $items]);
51	    }
52	
53	    /**
54	     * POST /api/v1/reports/definitions
55	     *
56	     * Create a new report definition.
57	     */
58	    public function createDefinition(ReportService $reportService): Response
59	    {
60	        $allowed = ['operations_analyst', 'finance_clerk', 'administrator'];
61	        if (empty(array_intersect($this->request->roles, $allowed))) {
62	            return $this->error('FORBIDDEN_ROLE', 'You do not have permission to create report definitions.', [], 403);
63	        }
64	
65	        $input = json_decode($this->request->getInput(), true) ?: [];
66	
67	        try {
68	            validate(ReportDefinitionValidate::class)->check($input);
69	        } catch (ValidateException $e) {
70	            return $this->error('VALIDATION_FAILED', $e->getMessage(), [], 422);
71	        }
72	
73	        unset($input['created_by']);
74	
75	        // Map frontend keys to service keys
76	        $input['dimensions_json'] = $input['dimensions_json'] ?? $input['dimensions'] ?? null;
77	        $input['filters_json'] = $input['filters_json'] ?? $input['filters'] ?? null;
78	        $input['columns_json'] = $input['columns_json'] ?? $input['columns'] ?? null;
79	
80	        $definition = $reportService->createDefinition($input, $this->request->userId);
81	
82	        return $this->success([
83	            'id'      => $definition['id'] ?? null,
84	            'message' => 'Report definition created.',
85	        ], 201);
86	    }
