88	    /**
89	     * GET /api/v1/reports/definitions/:id
90	     *
91	     * Read a report definition.
92	     */
93	    public function readDefinition($id, ReportService $reportService): Response
94	    {
95	        $allowed = ['operations_analyst', 'finance_clerk', 'administrator', 'auditor'];
96	        if (empty(array_intersect($this->request->roles, $allowed))) {
97	            return $this->error('FORBIDDEN_ROLE', 'You do not have permission to read report definitions.', [], 403);
98	        }
99	
100	        $definition = $reportService->findDefinition((int) $id);
101	
102	        if (!$definition) {
103	            return $this->error('NOT_FOUND', 'Report definition not found.', [], 404);
104	        }
105	
106	        // Ownership check: non-privileged users can only see their own definitions
107	        if (!$this->isPrivilegedOrOwner($definition)) {
108	            return $this->error('NOT_FOUND', 'Report definition not found.', [], 404);
