358	    /**
359	     * GET /api/v1/reports/export-csv
360	     *
361	     * Export report data as CSV.
362	     */
363	    public function exportCsv(
364	        CsvExportService $csvExportService,
365	        AuditService $auditService,
366	        FieldMaskingService $fieldMaskingService
367	    ): Response {
368	        $allowed = ['operations_analyst', 'finance_clerk', 'administrator'];
369	        if (empty(array_intersect($this->request->roles, $allowed))) {
370	            return $this->error('FORBIDDEN_ROLE', 'You do not have permission to export reports.', [], 403);
371	        }
372	
373	        $input = json_decode($this->request->getInput(), true) ?: [];
374	
375	        $type    = $input['type'] ?? '';
376	        $filters = $input['filters'] ?? [];
377	
378	        $allowedTypes = ['orders', 'participants', 'recipes', 'settlement_statements'];
379	        if (!in_array($type, $allowedTypes, true)) {
380	            return $this->error('VALIDATION_FAILED', 'Export type must be one of: ' . implode(', ', $allowedTypes), [], 422);
381	        }
382	
383	        $siteScopes = $this->request->siteScopes ?? [];
384	        $userRoles  = $this->request->roles ?? [];
385	
386	        // Query data server-side based on type and filters
387	        $query = Db::name($type);
388	
389	        // Apply site scope filtering
390	        if (!empty($siteScopes)) {
391	            $query->whereIn('site_id', $siteScopes);
392	        }
393	
394	        // Apply user-provided filters
395	        if (!empty($filters['date_from'])) {
396	            $query->where('created_at', '>=', $filters['date_from']);
397	        }
398	        if (!empty($filters['date_to'])) {
399	            $query->where('created_at', '<=', $filters['date_to']);
400	        }
401	        if (!empty($filters['status'])) {
402	            $query->where('status', $filters['status']);
403	        }
404	        if (!empty($filters['site_id']) && in_array($filters['site_id'], $siteScopes, true)) {
405	            $query->where('site_id', $filters['site_id']);
406	        }
407	
408	        $data = $query->select()->toArray();
409	
410	        if (empty($data)) {
411	            return $this->error('VALIDATION_FAILED', 'No data found for the given type and filters.', [], 422);
412	        }
413	
414	        // Determine columns from data keys
415	        $columns = array_keys($data[0]);
416	
417	        // Apply field masking via FieldMaskingService
418	        $sensitiveFields = ['phone', 'tax_id', 'tax_id_encrypted', 'password_hash', 'email', 'national_id', 'bank_account'];
419	        $maskableFields  = array_intersect($sensitiveFields, $columns);
420	
421	        $maskedData = array_map(function (array $row) use ($fieldMaskingService, $maskableFields, $userRoles) {
422	            return $fieldMaskingService->applyMaskingToRecord($row, $maskableFields, $userRoles);
423	        }, $data);
424	
425	        $filePath = $csvExportService->generateCsv($maskedData, $columns, []);
426	
427	        if (empty($filePath) || !file_exists($filePath)) {
428	            return $this->error('NOT_FOUND', 'Failed to generate CSV export.', [], 500);
429	        }
430	
431	        $recordCount = count($maskedData);
432	
433	        $auditService->log(
434	            'report.export_csv',
435	            $this->request->userId,
436	            $this->request->roles[0] ?? 'unknown',
437	            !empty($siteScopes) ? $siteScopes[0] : null,
438	            'csv_export',
439	            null,
440	            $this->request->requestId,
441	            "Server-side {$type} CSV export with {$recordCount} rows"
442	        );
443	
444	        ExportLog::create([
445	            'actor_id'     => $this->request->userId,
446	            'site_id'      => !empty($siteScopes) ? $siteScopes[0] : null,
447	            'export_type'  => $type . '_csv',
448	            'record_count' => $recordCount,
449	            'reason'       => "Server-side {$type} CSV export",
450	            'request_id'   => $this->request->requestId,
451	        ]);
452	
453	        return download($filePath);
454	    }
455	}
