121	    /**
122	     * Execute a report run: query data, generate CSV, create artifact record.
123	     *
124	     * @param int $runId
125	     * @return void
126	     */
127	    public function executeRun(int $runId): void
128	    {
129	        $run = Db::table('report_runs')->where('id', $runId)->find();
130	        if (!$run) {
131	            throw new ValidateException('Report run not found.');
132	        }
133	
134	        $definition = Db::table('report_definitions')->where('id', $run['definition_id'])->find();
135	        if (!$definition) {
136	            Db::table('report_runs')->where('id', $runId)->update([
137	                'status' => 'failed',
138	                'completed_at' => date('Y-m-d H:i:s'),
139	            ]);
140	            return;
141	        }
142	
143	        Db::table('report_runs')->where('id', $runId)->update([
144	            'status' => 'running',
145	            'started_at' => date('Y-m-d H:i:s'),
146	        ]);
147	
148	        try {
149	            $dimensions = !empty($definition['dimensions_json'])
150	                ? json_decode($definition['dimensions_json'], true) : [];
151	            $filters = !empty($definition['filters_json'])
152	                ? json_decode($definition['filters_json'], true) : [];
153	            $columns = !empty($definition['columns_json'])
154	                ? json_decode($definition['columns_json'], true) : [];
155	
156	            $reportType = $dimensions['type'] ?? ($filters['type'] ?? 'general');
157	
158	            $data = $this->queryReportData($reportType, $dimensions, $filters);
159	
160	            $csvColumns = !empty($columns) ? $columns : (!empty($data) ? array_keys($data[0]) : []);
161	
162	            $filePath = $this->csvExportService->generateCsv($data, $csvColumns, []);
163	
164	            $now = date('Y-m-d H:i:s');
165	            $expiresAt = date('Y-m-d H:i:s', strtotime('+180 days'));
166	
167	            // report_artifacts schema: run_id, file_path, file_size, sha256_hash, created_at
168	            $fileSize = file_exists($filePath) ? filesize($filePath) : 0;
169	            $sha256 = file_exists($filePath) ? hash_file('sha256', $filePath) : '';
170	
171	            Db::table('report_artifacts')->insert([
172	                'run_id'      => $runId,
173	                'file_path'   => $filePath,
174	                'file_size'   => $fileSize,
175	                'sha256_hash' => $sha256,
176	                'created_at'  => $now,
177	            ]);
178	
179	            // report_runs schema: artifact_path, expires_at, started_at, completed_at
180	            Db::table('report_runs')->where('id', $runId)->update([
181	                'status'        => 'succeeded',
182	                'artifact_path' => $filePath,
183	                'expires_at'    => $expiresAt,
184	                'completed_at'  => $now,
185	            ]);
186	        } catch (\Throwable $e) {
187	            Db::table('report_runs')->where('id', $runId)->update([
188	                'status'       => 'failed',
189	                'completed_at' => date('Y-m-d H:i:s'),
190	            ]);
191	            throw $e;
192	        }
193	    }
