195	    /**
196	     * Query report data based on the report type and definition parameters.
197	     *
198	     * @param string $reportType
199	     * @param array  $dimensions
200	     * @param array  $filters
201	     * @return array
202	     */
203	    private function queryReportData(string $reportType, array $dimensions, array $filters): array
204	    {
205	        $query = null;
206	
207	        switch ($reportType) {
208	            case 'participation':
209	                $query = Db::table('participants')
210	                    ->field('site_id, COUNT(*) as participant_count')
211	                    ->group('site_id');
212	                break;
213	
214	            case 'retention':
215	                $query = Db::table('participants')
216	                    ->alias('p')
217	                    ->leftJoin('orders o', 'o.participant_id = p.id')
218	                    ->field('p.id, p.name, COUNT(o.id) as order_count, IF(COUNT(o.id) > 1, "repeat", "one-time") as participant_type')
219	                    ->group('p.id, p.name');
220	                break;
221	
222	            case 'pass_rate':
223	                $query = Db::table('recipes')
224	                    ->field('status, COUNT(*) as recipe_count, ROUND(COUNT(CASE WHEN status = "approved" THEN 1 END) * 100.0 / COUNT(*), 2) as approval_rate')
225	                    ->group('status');
226	                break;
227	
228	            case 'regional_distribution':
229	                $query = Db::table('orders')
230	                    ->alias('o')
231	                    ->leftJoin('participants p', 'p.id = o.participant_id')
232	                    ->field('o.site_id, COUNT(DISTINCT o.id) as order_count, COUNT(DISTINCT o.participant_id) as participant_count')
233	                    ->group('o.site_id');
234	                break;
235	
236	            default:
237	                // General report: determine table from dimensions or default to orders
238	                $table = $dimensions['table'] ?? 'orders';
239	                $allowedTables = ['orders', 'participants', 'recipes', 'settlement_statements'];
240	                if (!in_array($table, $allowedTables, true)) {
241	                    $table = 'orders';
242	                }
243	                $query = Db::table($table);
244	                break;
245	        }
246	
247	        // Apply common filters
248	        if (!empty($filters['site_id'])) {
249	            $siteCol = in_array($reportType, ['retention']) ? 'p.site_id' : 'site_id';
250	            $query->where($siteCol, $filters['site_id']);
251	        }
252	        if (!empty($filters['site_ids']) && is_array($filters['site_ids'])) {
253	            $siteCol = in_array($reportType, ['retention']) ? 'p.site_id' : 'site_id';
254	            $query->whereIn($siteCol, $filters['site_ids']);
255	        }
256	        if (!empty($filters['date_from'])) {
257	            $dateCol = in_array($reportType, ['retention']) ? 'p.created_at' : 'created_at';
258	            $query->where($dateCol, '>=', $filters['date_from']);
259	        }
260	        if (!empty($filters['date_to'])) {
261	            $dateCol = in_array($reportType, ['retention']) ? 'p.created_at' : 'created_at';
262	            $query->where($dateCol, '<=', $filters['date_to']);
263	        }
264	        if (!empty($filters['status'])) {
265	            $query->where('status', $filters['status']);
266	        }
267	
268	        return $query->select()->toArray();
269	    }
270	
271	    /**
272	     * Get a report run by ID, including artifact info if available.
273	     *
274	     * @param int $id
275	     * @return array|null Run data or null if not found.
276	     */
277	    public function getRun(int $id): ?array
278	    {
279	        $run = Db::table('report_runs')->where('id', $id)->find();
280	        if (!$run) {
281	            return null;
282	        }
283	
284	        $artifact = Db::table('report_artifacts')->where('run_id', $id)->find();
285	        if ($artifact) {
286	            $run['artifact'] = $artifact;
287	        }
288	
289	        return $run;
290	    }
291	
292	    /**
293	     * List report runs, optionally filtered.
294	     *
295	     * @param array $filters Query filters (definition_id, status, page, per_page).
296	     * @return array Paginated list of run records.
297	     */
298	    public function listRuns(array $filters): array
299	    {
300	        $page = max(1, (int) ($filters['page'] ?? 1));
301	        $perPage = min(100, max(1, (int) ($filters['per_page'] ?? 20)));
302	
303	        $query = Db::table('report_runs')->alias('r');
304	
305	        // Ownership scoping: non-privileged users only see runs for their own definitions
306	        $userRoles = $filters['user_roles'] ?? [];
307	        $privilegedRoles = ['administrator', 'auditor'];
308	        if (!empty($filters['user_id']) && empty(array_intersect($userRoles, $privilegedRoles))) {
309	            $query->join('report_definitions d', 'r.definition_id = d.id')
310	                  ->where('d.created_by', $filters['user_id']);
311	        }
312	
313	        if (!empty($filters['definition_id'])) {
314	            $query->where('r.definition_id', $filters['definition_id']);
315	        }
316	        if (!empty($filters['status'])) {
317	            $query->where('r.status', $filters['status']);
318	        }
319	
320	        $total = (clone $query)->count();
321	
322	        $rows = $query->field('r.*')
323	            ->order('r.created_at', 'desc')
324	            ->limit(($page - 1) * $perPage, $perPage)
325	            ->select()
326	            ->toArray();
327	
328	        return [
329	            'data' => $rows,
330	            'total' => $total,
331	            'page' => $page,
332	            'per_page' => $perPage,
333	        ];
334	    }
335	
336	    /**
337	     * Schedule recurring execution of a report definition.
338	     *
339	     * @param int   $definitionId
340	     * @param array $schedule Schedule configuration (cadence, next_run_at, active).
341	     * @return void
342	     */
343	    public function scheduleReport(int $definitionId, array $schedule): void
344	    {
345	        $definition = Db::table('report_definitions')->where('id', $definitionId)->find();
346	        if (!$definition) {
347	            throw new ValidateException('Report definition not found.');
348	        }
349	
350	        $existing = Db::table('report_schedules')
351	            ->where('definition_id', $definitionId)
352	            ->find();
353	
354	        $now = date('Y-m-d H:i:s');
355	
356	        // Ensure next_run_at is set so the schedule is immediately runnable
357	        if (empty($schedule['next_run_at'])) {
358	            $schedule['next_run_at'] = $now;
359	        }
360	
361	        if ($existing) {
362	            $update = ['updated_at' => $now];
363	            if (isset($schedule['cadence'])) {
364	                $update['cadence'] = $schedule['cadence'];
365	            }
366	            if (isset($schedule['next_run_at'])) {
367	                $update['next_run_at'] = $schedule['next_run_at'];
368	            }
369	            if (isset($schedule['active'])) {
370	                $update['active'] = $schedule['active'] ? 1 : 0;
371	            }
372	            Db::table('report_schedules')->where('id', $existing['id'])->update($update);
373	        } else {
374	            Db::table('report_schedules')->insert([
375	                'definition_id' => $definitionId,
376	                'cadence' => $schedule['cadence'] ?? 'daily',
377	                'next_run_at' => $schedule['next_run_at'] ?? null,
378	                'active' => isset($schedule['active']) ? ($schedule['active'] ? 1 : 0) : 1,
379	                'created_at' => $now,
380	                'updated_at' => $now,
381	            ]);
382	        }
383	    }
384	}
