2	declare(strict_types=1);
3	
4	namespace app\service\recipe;
5	
6	use think\facade\Db;
7	use think\exception\ValidateException;
8	
9	class WorkflowService
10	{
11	    /**
12	     * Valid state transitions mapped using DB status values.
13	     */
14	    private const TRANSITIONS = [
15	        'draft'     => ['in_review'],
16	        'in_review' => ['approved', 'rejected'],
17	    ];
18	
19	    /**
20	     * Submit a recipe version for review.
21	     * Transitions: draft -> in_review.
22	     *
23	     * @param int $versionId
24	     * @param int $userId
25	     * @return void
26	     * @throws ValidateException If the current state does not allow this transition.
27	     */
28	    public function submitForReview(int $versionId, int $userId): void
29	    {
30	        $currentState = $this->resolveCurrentState($versionId);
31	        $this->assertTransition($currentState, 'in_review');
32	
33	        $now = date('Y-m-d H:i:s');
34	        $version = Db::table('recipe_versions')->where('id', $versionId)->find();
35	
36	        Db::table('recipe_versions')
37	            ->where('id', $versionId)
38	            ->update(['status' => 'in_review', 'updated_at' => $now]);
39	
40	        // Also update the recipe-level status
41	        if ($version) {
42	            Db::table('recipes')
43	                ->where('id', $version['recipe_id'])
44	                ->update(['status' => 'in_review', 'updated_at' => $now]);
45	        }
46	    }
47	
48	    /**
49	     * Approve a recipe version.
50	     * Transitions: in_review -> approved.
51	     *
52	     * @param int         $versionId
53	     * @param int         $reviewerId
54	     * @param string|null $comment
55	     * @return void
56	     * @throws ValidateException If the current state does not allow this transition.
57	     */
58	    public function approve(int $versionId, int $reviewerId, ?string $comment = null): void
59	    {
60	        $currentState = $this->resolveCurrentState($versionId);
61	        $this->assertTransition($currentState, 'approved');
62	
63	        $now = date('Y-m-d H:i:s');
64	
65	        Db::startTrans();
66	        try {
67	            Db::table('recipe_versions')
68	                ->where('id', $versionId)
69	                ->update([
70	                    'status' => 'approved',
71	                    'reviewer_id' => $reviewerId,
72	                    'reviewed_at' => $now,
73	                    'updated_at' => $now,
74	                ]);
75	
76	            Db::table('review_actions')->insert([
77	                'version_id' => $versionId,
78	                'reviewer_id' => $reviewerId,
79	                'action' => 'approved',
80	                'comment' => $comment,
81	                'created_at' => $now,
82	            ]);
83	
84	            Db::commit();
85	        } catch (\Throwable $e) {
86	            Db::rollback();
87	            throw $e;
88	        }
89	    }
90	
91	    /**
92	     * Reject a recipe version.
93	     * Transitions: in_review -> rejected.
94	     *
95	     * @param int         $versionId
96	     * @param int         $reviewerId
97	     * @param string|null $comment
98	     * @return void
99	     * @throws ValidateException If the current state does not allow this transition.
100	     */
101	    public function reject(int $versionId, int $reviewerId, ?string $comment = null): void
102	    {
103	        $currentState = $this->resolveCurrentState($versionId);
104	        $this->assertTransition($currentState, 'rejected');
105	
106	        $now = date('Y-m-d H:i:s');
107	
108	        Db::startTrans();
109	        try {
110	            Db::table('recipe_versions')
111	                ->where('id', $versionId)
112	                ->update([
113	                    'status' => 'rejected',
114	                    'reviewer_id' => $reviewerId,
115	                    'reviewed_at' => $now,
116	                    'updated_at' => $now,
117	                ]);
118	
119	            Db::table('review_actions')->insert([
120	                'version_id' => $versionId,
121	                'reviewer_id' => $reviewerId,
122	                'action' => 'rejected',
123	                'comment' => $comment,
124	                'created_at' => $now,
125	            ]);
126	
127	            Db::commit();
128	        } catch (\Throwable $e) {
129	            Db::rollback();
130	            throw $e;
131	        }
132	    }
133	
134	    /**
135	     * Publish an approved recipe version.
136	     * Sets published_version_id on the recipe and updates recipe status.
137	     *
138	     * @param int $recipeId
139	     * @param int $userId
140	     * @return void
141	     * @throws ValidateException If no approved version exists for the recipe.
142	     */
143	    public function publish(int $recipeId, int $userId): void
144	    {
145	        // Find the latest approved version for this recipe
146	        $version = Db::table('recipe_versions')
147	            ->where('recipe_id', $recipeId)
148	            ->where('status', 'approved')
149	            ->order('version_number', 'desc')
150	            ->find();
151	
152	        if (!$version) {
153	            throw new ValidateException('Only approved versions can be published.');
154	        }
155	
156	        Db::table('recipes')
157	            ->where('id', $recipeId)
158	            ->update([
159	                'published_version_id' => $version['id'],
160	                'status' => 'published',
161	                'updated_at' => date('Y-m-d H:i:s'),
162	            ]);
163	    }
164	
165	    /**
166	     * Resolve the current workflow state of a recipe version.
167	     *
168	     * @param int $versionId
169	     * @return string Current state name (draft, in_review, approved, rejected).
170	     * @throws ValidateException If version not found.
171	     */
172	    private function resolveCurrentState(int $versionId): string
173	    {
174	        $version = Db::table('recipe_versions')
175	            ->where('id', $versionId)
176	            ->field('status')
177	            ->find();
178	
179	        if (!$version) {
180	            throw new ValidateException('Recipe version not found.');
181	        }
182	
183	        return $version['status'];
184	    }
185	
186	    /**
187	     * Assert that a transition from the current state to the target state is valid.
188	     *
189	     * @param string $currentState
190	     * @param string $targetState
191	     * @return void
192	     * @throws ValidateException If the transition is not allowed.
193	     */
194	    private function assertTransition(string $currentState, string $targetState): void
195	    {
196	        $allowed = self::TRANSITIONS[$currentState] ?? [];
197	        if (!in_array($targetState, $allowed, true)) {
198	            throw new ValidateException(
199	                "Invalid state transition: {$currentState} -> {$targetState}"
200	            );
201	        }
202	    }
203	}
