7	
8	class RecipeVersionValidate extends Validate
9	{
10	    private const VALID_UNITS = ['g', 'kg', 'ml', 'l', 'tsp', 'tbsp', 'piece', 'pcs'];
11	
12	    protected $rule = [
13	        'total_time'  => 'require|integer|between:1,720',
14	        'difficulty'  => 'in:easy,medium,hard',
15	        'steps'       => 'array|min:1|max:50',
16	        'ingredients' => 'array|min:1',
17	    ];
18	
19	    protected $message = [
20	        'total_time.require' => 'Total time is required',
21	        'total_time.integer' => 'Total time must be an integer',
22	        'total_time.between' => 'Total time must be between 1 and 720 minutes',
23	        'difficulty.in'      => 'Difficulty must be one of: easy, medium, hard',
24	        'steps.array'        => 'Steps must be an array',
25	        'steps.min'          => 'At least 1 step is required',
26	        'steps.max'          => 'Maximum 50 steps allowed',
27	        'ingredients.array'  => 'Ingredients must be an array',
28	        'ingredients.min'    => 'At least 1 ingredient is required',
29	    ];
30	
31	    /**
32	     * Validate individual ingredient entries after standard rule checks.
33	     * Called from the controller when ingredients are present.
34	     */
35	    public static function validateIngredients(array $ingredients): ?string
36	    {
37	        foreach ($ingredients as $i => $ing) {
38	            if (empty($ing['name'])) {
39	                return "Ingredient #" . ($i + 1) . ": name is required";
40	            }
41	            if (!isset($ing['quantity']) || !is_numeric($ing['quantity']) || (float)$ing['quantity'] <= 0) {
42	                return "Ingredient #" . ($i + 1) . ": quantity must be a number greater than 0";
43	            }
44	            if (empty($ing['unit']) || !in_array($ing['unit'], self::VALID_UNITS, true)) {
45	                return "Ingredient #" . ($i + 1) . ": unit must be one of: " . implode(', ', self::VALID_UNITS);
46	            }
47	        }
48	        return null;
49	    }
50	}
