4	namespace tests;
5	
6	use PHPUnit\Framework\TestCase as BaseTestCase;
7	
8	abstract class TestCase extends BaseTestCase
9	{
10	    /** @var string[] Cookie files to clean up after each test */
11	    private array $cookieFiles = [];
12	
13	    protected function tearDown(): void
14	    {
15	        foreach ($this->cookieFiles as $file) {
16	            if (file_exists($file)) {
17	                @unlink($file);
18	            }
19	        }
20	        $this->cookieFiles = [];
21	        parent::tearDown();
22	    }
23	
24	    /**
25	     * Make an HTTP request to the running application.
26	     * With host networking, the app listens on 127.0.0.1:8080 both
27	     * from inside the container and from the host.
28	     */
29	    protected function httpRequest(string $method, string $path, array $data = [], array $headers = []): array
30	    {
31	        $url = 'http://127.0.0.1:8080' . $path;
32	
33	        $ch = curl_init();
34	        curl_setopt($ch, CURLOPT_URL, $url);
35	        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
36	        curl_setopt($ch, CURLOPT_TIMEOUT, 10);
37	        curl_setopt($ch, CURLOPT_CUSTOMREQUEST, strtoupper($method));
38	        curl_setopt($ch, CURLOPT_HTTPHEADER, array_merge(
39	            ['Content-Type: application/json', 'Accept: application/json'],
40	            $headers
41	        ));
42	
43	        if (!empty($data) && in_array(strtoupper($method), ['POST', 'PUT', 'PATCH'])) {
44	            curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($data));
45	        }
46	
47	        $response = curl_exec($ch);
48	        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
49	        curl_close($ch);
50	
51	        return [
52	            'status' => $httpCode,
53	            'body' => json_decode($response ?: '', true) ?? [],
54	            'raw' => $response,
55	        ];
56	    }
57	
58	    /**
59	     * Log in as a seeded user and return session credentials.
60	     *
61	     * @param string $username One of: admin, editor, reviewer, analyst, finance, auditor
62	     * @return array{cookie_file: string, csrf_token: string, user: array}
63	     */
64	    protected function loginAs(string $username): array
65	    {
66	        $password = bootstrap_config('seed_admin_password', '');
67	
68	        $cookieFile = tempnam(sys_get_temp_dir(), 'test_cookie_');
69	        $this->cookieFiles[] = $cookieFile;
70	
71	        $ch = curl_init('http://127.0.0.1:8080/api/v1/auth/login');
72	        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
73	        curl_setopt($ch, CURLOPT_TIMEOUT, 10);
74	        curl_setopt($ch, CURLOPT_POST, true);
75	        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode([
76	            'username' => $username,
77	            'password' => $password,
78	        ]));
79	        curl_setopt($ch, CURLOPT_HTTPHEADER, [
80	            'Content-Type: application/json',
81	            'Accept: application/json',
82	        ]);
83	        curl_setopt($ch, CURLOPT_COOKIEJAR, $cookieFile);
84	        curl_setopt($ch, CURLOPT_COOKIEFILE, $cookieFile);
85	
86	        $response = curl_exec($ch);
87	        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
88	        curl_close($ch);
89	
90	        $body = json_decode($response ?: '', true) ?? [];
91	
92	        return [
93	            'cookie_file' => $cookieFile,
94	            'csrf_token'  => $body['data']['csrf_token'] ?? '',
95	            'user'        => $body['data']['user'] ?? [],
96	            'status'      => $httpCode,
97	        ];
98	    }
99	
100	    /**
101	     * Make an authenticated HTTP request using session credentials from loginAs().
102	     *
103	     * @param string $method  HTTP method (GET, POST, PUT, PATCH, DELETE)
104	     * @param string $path    URL path (e.g. /api/v1/recipes)
105	     * @param array  $session Session credentials from loginAs()
106	     * @param array  $data    Request body data (for POST/PUT/PATCH)
107	     * @return array{status: int, body: array, raw: string}
108	     */
109	    protected function authenticatedRequest(string $method, string $path, array $session, array $data = []): array
110	    {
111	        $url = 'http://127.0.0.1:8080' . $path;
112	
113	        $ch = curl_init($url);
114	        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
115	        curl_setopt($ch, CURLOPT_TIMEOUT, 10);
116	        curl_setopt($ch, CURLOPT_CUSTOMREQUEST, strtoupper($method));
117	        curl_setopt($ch, CURLOPT_COOKIEFILE, $session['cookie_file']);
118	        curl_setopt($ch, CURLOPT_COOKIEJAR, $session['cookie_file']);
119	
120	        $headers = ['Content-Type: application/json', 'Accept: application/json'];
121	        if (!empty($session['csrf_token'])) {
122	            $headers[] = 'X-CSRF-Token: ' . $session['csrf_token'];
123	        }
124	        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
125	
126	        if (!empty($data) && in_array(strtoupper($method), ['POST', 'PUT', 'PATCH'])) {
127	            curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($data));
128	        }
129	
130	        $response = curl_exec($ch);
131	        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
132	        curl_close($ch);
133	
134	        return [
135	            'status' => $httpCode,
136	            'body'   => json_decode($response ?: '', true) ?? [],
137	            'raw'    => $response,
138	        ];
139	    }
140	}
