1	<?php
2	declare(strict_types=1);
3	
4	namespace tests\Feature\Reports;
5	
6	use tests\TestCase;
7	
8	/**
9	 * Tests report definition and run scope isolation.
10	 *
11	 * Verifies that:
12	 * - Non-privileged users can only see their own report definitions
13	 * - Administrators can see all report definitions
14	 *
15	 * ZERO markTestSkipped / markTestIncomplete calls.
16	 */
17	class ReportScopeTest extends TestCase
18	{
19	    private array $analystSession;
20	    private array $financeSession;
21	    private array $adminSession;
22	
23	    protected function setUp(): void
24	    {
25	        parent::setUp();
26	        $this->analystSession  = $this->loginAs('analyst');
27	        $this->financeSession  = $this->loginAs('finance');
28	        $this->adminSession    = $this->loginAs('admin');
29	    }
30	
31	    // ------------------------------------------------------------------
32	    // Ownership scoping
33	    // ------------------------------------------------------------------
34	
35	    public function testUserCanOnlySeeOwnDefinitions(): void
36	    {
37	        // Analyst creates a report definition
38	        $createResponse = $this->authenticatedRequest('POST', '/api/v1/reports/definitions', $this->analystSession, [
39	            'name'        => 'Analyst Scoped Report ' . uniqid(),
40	            'description' => 'Created by analyst for scope test',
41	        ]);
42	        $this->assertEquals(201, $createResponse['status'],
43	            'Analyst should be able to create report definition. Got: ' . ($createResponse['raw'] ?? ''));
44	        $analystDefId = $createResponse['body']['data']['id'] ?? null;
45	        $this->assertNotNull($analystDefId, 'Report definition ID must be returned');
46	
47	        // Finance lists definitions -- should NOT see the analyst's definition
48	        $financeListResponse = $this->authenticatedRequest('GET', '/api/v1/reports/definitions', $this->financeSession);
49	        $this->assertEquals(200, $financeListResponse['status']);
50	        $financeItems = $financeListResponse['body']['data']['items'] ?? [];
51	
52	        $found = false;
53	        foreach ($financeItems as $item) {
54	            if (($item['id'] ?? null) == $analystDefId) {
55	                $found = true;
56	                break;
57	            }
58	        }
59	        $this->assertFalse($found,
60	            "Finance user should NOT see analyst's report definition (id={$analystDefId}) in their list");
61	
62	        // Finance tries to read the analyst's definition directly -- should get 404
63	        $financeReadResponse = $this->authenticatedRequest('GET', "/api/v1/reports/definitions/{$analystDefId}", $this->financeSession);
64	        $this->assertEquals(404, $financeReadResponse['status'],
65	            'Finance user should not be able to read analyst\'s definition directly');
66	    }
67	
68	    public function testAdminCanSeeAllDefinitions(): void
69	    {
70	        // Analyst creates a report definition
71	        $createResponse = $this->authenticatedRequest('POST', '/api/v1/reports/definitions', $this->analystSession, [
72	            'name'        => 'Admin Visibility Report ' . uniqid(),
73	            'description' => 'Created by analyst, should be visible to admin',
74	        ]);
75	        $this->assertEquals(201, $createResponse['status']);
76	        $defId = $createResponse['body']['data']['id'] ?? null;
77	        $this->assertNotNull($defId);
78	
79	        // Admin lists definitions -- should see the analyst's definition
80	        $adminListResponse = $this->authenticatedRequest('GET', '/api/v1/reports/definitions', $this->adminSession);
81	        $this->assertEquals(200, $adminListResponse['status']);
82	        $adminItems = $adminListResponse['body']['data']['items'] ?? [];
83	
84	        $found = false;
85	        foreach ($adminItems as $item) {
86	            if (($item['id'] ?? null) == $defId) {
87	                $found = true;
88	                break;
89	            }
90	        }
91	        $this->assertTrue($found,
92	            "Admin should see analyst's report definition (id={$defId}) in their list");
93	
94	        // Admin can also read the definition directly
95	        $adminReadResponse = $this->authenticatedRequest('GET', "/api/v1/reports/definitions/{$defId}", $this->adminSession);
96	        $this->assertEquals(200, $adminReadResponse['status'],
97	            'Admin should be able to read any report definition');
98	    }
99	
100	    // ------------------------------------------------------------------
101	    // Cross-user scope isolation
102	    // ------------------------------------------------------------------
103	
104	    public function testCannotReadOthersDefinition(): void
105	    {
106	        // Analyst creates a definition
107	        $createResponse = $this->authenticatedRequest('POST', '/api/v1/reports/definitions', $this->analystSession, [
108	            'name'        => 'Analyst Private Def ' . uniqid(),
109	            'description' => 'Should not be readable by finance',
110	        ]);
111	        $this->assertEquals(201, $createResponse['status']);
112	        $defId = $createResponse['body']['data']['id'] ?? null;
113	        $this->assertNotNull($defId);
114	
115	        // Finance tries to read it directly -- should get 404
116	        $readResponse = $this->authenticatedRequest('GET', "/api/v1/reports/definitions/{$defId}", $this->financeSession);
117	        $this->assertEquals(404, $readResponse['status'],
118	            'Finance should not be able to read analyst\'s definition');
119	    }
120	
121	    public function testCannotUpdateOthersDefinition(): void
122	    {
123	        // Analyst creates a definition
124	        $createResponse = $this->authenticatedRequest('POST', '/api/v1/reports/definitions', $this->analystSession, [
125	            'name'        => 'Analyst Update Scope ' . uniqid(),
126	            'description' => 'Should not be updatable by finance',
127	        ]);
128	        $this->assertEquals(201, $createResponse['status']);
129	        $defId = $createResponse['body']['data']['id'] ?? null;
130	        $this->assertNotNull($defId);
131	
132	        // Finance tries to update it -- should get 403 or 404
133	        $updateResponse = $this->authenticatedRequest('PATCH', "/api/v1/reports/definitions/{$defId}", $this->financeSession, [
134	            'name' => 'Hijacked Name',
