10	use app\service\report\ReportService;
11	
12	class ScheduledReportJob extends Command
13	{
14	    protected function configure()
15	    {
16	        $this->setName('reports:scheduled')
17	            ->setDescription('Process scheduled report generation');
18	    }
19	
20	    protected function execute(Input $input, Output $output)
21	    {
22	        $output->writeln('[' . date('Y-m-d H:i:s') . '] Scheduled report processing started.');
23	        Log::info('Scheduled report processing started.');
24	
25	        try {
26	            // Query report schedules that are due for execution
27	            $dueSchedules = Db::name('report_schedules')
28	                ->where('active', true)
29	                ->where('next_run_at', '<=', date('Y-m-d H:i:s'))
30	                ->select();
31	
32	            $count = count($dueSchedules);
33	            $output->writeln("Found {$count} scheduled report(s) due for processing.");
34	            Log::info("Found {$count} scheduled report(s) due for processing.");
35	
36	            $reportService = app(ReportService::class);
37	
38	            foreach ($dueSchedules as $schedule) {
39	                try {
40	                    // Queue a report run for each due schedule
41	                    $runId = Db::name('report_runs')->insertGetId([
42	                        'definition_id' => $schedule['definition_id'],
43	                        'status'        => 'queued',
44	                        'created_at'    => date('Y-m-d H:i:s'),
45	                    ]);
46	
47	                    $output->writeln("Queued report run #{$runId} for schedule #{$schedule['id']} (definition #{$schedule['definition_id']}).");
48	                    Log::info("Queued report run #{$runId} for schedule #{$schedule['id']}.");
49	
50	                    // Execute the report run
51	                    $reportService->executeRun($runId);
52	
53	                    $output->writeln("Executed report run #{$runId} for schedule #{$schedule['id']}.");
54	                    Log::info("Executed report run #{$runId} for schedule #{$schedule['id']}.");
55	
56	                    // Advance next_run_at based on cadence
57	                    $cadence = $schedule['cadence'] ?? 'daily';
58	                    $currentNextRun = $schedule['next_run_at'] ?? date('Y-m-d H:i:s');
59	                    switch ($cadence) {
60	                        case 'weekly':
61	                            $newNextRun = date('Y-m-d H:i:s', strtotime($currentNextRun . ' +7 days'));
62	                            break;
63	                        case 'monthly':
64	                            $newNextRun = date('Y-m-d H:i:s', strtotime($currentNextRun . ' +1 month'));
65	                            break;
66	                        case 'daily':
67	                        default:
68	                            $newNextRun = date('Y-m-d H:i:s', strtotime($currentNextRun . ' +1 day'));
69	                            break;
70	                    }
71	
72	                    Db::name('report_schedules')
73	                        ->where('id', $schedule['id'])
74	                        ->update([
75	                            'next_run_at' => $newNextRun,
76	                            'updated_at'  => date('Y-m-d H:i:s'),
77	                        ]);
78	
79	                    $output->writeln("Advanced schedule #{$schedule['id']} next_run_at to {$newNextRun}.");
80	                    Log::info("Advanced schedule #{$schedule['id']} next_run_at to {$newNextRun}.");
81	                } catch (\Exception $e) {
82	                    $output->writeln("<error>Failed to process report for schedule #{$schedule['id']}: {$e->getMessage()}</error>");
83	                    Log::error("Failed to process report for schedule #{$schedule['id']}: {$e->getMessage()}");
84	                }
85	            }
86	        } catch (\Exception $e) {
87	            $output->writeln('<error>Error processing scheduled reports: ' . $e->getMessage() . '</error>');
88	            Log::error('Error processing scheduled reports: ' . $e->getMessage(), [
89	                'trace' => $e->getTraceAsString(),
90	            ]);
91	        }
92	
93	        $output->writeln('[' . date('Y-m-d H:i:s') . '] Scheduled report processing completed.');
94	        Log::info('Scheduled report processing completed.');
95	    }
96	}
