2	declare(strict_types=1);
3	
4	namespace app\service\analytics;
5	
6	use think\facade\Db;
7	use think\exception\ValidateException;
8	
9	class AnalyticsService
10	{
11	    /**
12	     * Get aggregated dashboard data filtered by criteria and site scopes.
13	     *
14	     * @param array $filters    Query filters (date_start, date_end, site_id, community_id, group_leader_id, product_id).
15	     * @param array $siteScopes Site IDs the requesting user has access to.
16	     * @return array Dashboard data structure with computed metrics, snapshots, and definitions.
17	     */
18	    public function getDashboardData(array $filters, array $siteScopes): array
19	    {
20	        $dateStart = $filters['date_start'] ?? null;
21	        $dateEnd = $filters['date_end'] ?? null;
22	
23	        // Base order query builder with scope and date filtering
24	        $buildOrderQuery = function () use ($siteScopes, $filters, $dateStart, $dateEnd) {
25	            $q = Db::table('orders');
26	            if (!empty($siteScopes)) {
27	                $q->whereIn('site_id', $siteScopes);
28	            }
29	            if ($dateStart) {
30	                $q->where('created_at', '>=', $dateStart);
31	            }
32	            if ($dateEnd) {
33	                $q->where('created_at', '<=', $dateEnd);
34	            }
35	            if (!empty($filters['site_id'])) {
36	                $q->where('site_id', $filters['site_id']);
37	            }
38	            if (!empty($filters['community_id'])) {
39	                $q->whereExists(function ($sub) use ($filters) {
40	                    $sub->table('group_leaders')
41	                        ->whereColumn('group_leaders.id', 'orders.group_leader_id')
42	                        ->where('group_leaders.community_id', $filters['community_id']);
43	                });
44	            }
45	            if (!empty($filters['group_leader_id'])) {
46	                $q->where('group_leader_id', $filters['group_leader_id']);
47	            }
48	            return $q;
49	        };
50	
51	        // 1. Total sales
52	        $totalSales = (clone $buildOrderQuery())->sum('total_amount');
53	
54	        // 2. Order count
55	        $orderCount = (clone $buildOrderQuery())->count();
56	
57	        // 3. Average order value
58	        $avgOrderValue = $orderCount > 0 ? round((float) $totalSales / $orderCount, 2) : 0;
59	
60	        // 4. Refund rate
61	        $refundQuery = Db::table('refunds')
62	            ->alias('ref')
63	            ->join('orders o', 'o.id = ref.order_id');
64	        if (!empty($siteScopes)) {
65	            $refundQuery->whereIn('o.site_id', $siteScopes);
66	        }
67	        if ($dateStart) {
68	            $refundQuery->where('ref.created_at', '>=', $dateStart);
69	        }
70	        if ($dateEnd) {
71	            $refundQuery->where('ref.created_at', '<=', $dateEnd);
72	        }
73	        $refundCount = $refundQuery->count();
74	        $refundRate = $orderCount > 0 ? round($refundCount / $orderCount * 100, 2) : 0;
75	
76	        // 5. Repeat purchase rate
77	        $totalParticipants = (clone $buildOrderQuery())->field('participant_id')->distinct(true)->count();
78	        $repeatParticipants = 0;
79	        if ($totalParticipants > 0) {
80	            $repeatRows = (clone $buildOrderQuery())
81	                ->field('participant_id, COUNT(*) as cnt')
82	                ->group('participant_id')
83	                ->having('cnt > 1')
84	                ->select()
85	                ->toArray();
86	            $repeatParticipants = count($repeatRows);
87	        }
88	        $repeatPurchaseRate = $totalParticipants > 0
89	            ? round($repeatParticipants / $totalParticipants * 100, 2)
90	            : 0;
91	
92	        // 6. Group conversion (orders per group leader)
93	        $leaderStats = (clone $buildOrderQuery())
94	            ->field('group_leader_id, COUNT(*) as order_count, SUM(total_amount) as total')
95	            ->group('group_leader_id')
96	            ->order('total', 'desc')
97	            ->limit(20)
98	            ->select()
99	            ->toArray();
100	
101	        // Calculate group_conversion: percentage of leaders that have at least one order
102	        $totalLeaders = Db::table('group_leaders');
103	        if (!empty($siteScopes)) {
104	            $totalLeaders->whereIn('site_id', $siteScopes);
105	        }
106	        if (!empty($filters['site_id'])) {
107	            $totalLeaders->where('site_id', $filters['site_id']);
108	        }
109	        $totalLeadersCount = $totalLeaders->count();
110	
111	        $leadersWithOrders = count($leaderStats);
112	        $groupConversion = $totalLeadersCount > 0
113	            ? round($leadersWithOrders / $totalLeadersCount * 100, 2)
114	            : 0;
115	
116	        // 7. Product popularity
117	        $productQuery = Db::table('order_items')
118	            ->alias('oi')
119	            ->join('orders o', 'o.id = oi.order_id');
120	        if (!empty($siteScopes)) {
121	            $productQuery->whereIn('o.site_id', $siteScopes);
122	        }
123	        if ($dateStart) {
124	            $productQuery->where('o.created_at', '>=', $dateStart);
125	        }
126	        if ($dateEnd) {
127	            $productQuery->where('o.created_at', '<=', $dateEnd);
128	        }
129	        if (!empty($filters['product_id'])) {
130	            $productQuery->where('oi.product_id', $filters['product_id']);
131	        }
132	        $productPopularity = $productQuery
133	            ->field('oi.product_id, SUM(oi.quantity) as total_quantity, SUM(oi.subtotal) as total_revenue')
134	            ->group('oi.product_id')
135	            ->order('total_quantity', 'desc')
136	            ->limit(20)
137	            ->select()
138	            ->toArray();
139	
140	        // Metric snapshots
141	        $snapshotQuery = Db::table('metric_snapshots');
142	        if (!empty($siteScopes)) {
143	            $snapshotQuery->whereIn('site_id', $siteScopes);
144	        }
145	        if ($dateStart) {
146	            $snapshotQuery->where('snapshot_date', '>=', $dateStart);
147	        }
148	        if ($dateEnd) {
149	            $snapshotQuery->where('snapshot_date', '<=', $dateEnd);
150	        }
151	        $snapshots = $snapshotQuery->order('snapshot_date', 'desc')->limit(200)->select()->toArray();
152	
153	        // Metric definitions
154	        $metricService = new MetricService();
155	        $definitions = $metricService->getMetricDefinitions();
156	
157	        return [
158	            'metrics' => [
159	                'total_sales' => (float) $totalSales,
160	                'order_count' => $orderCount,
161	                'avg_order_value' => $avgOrderValue,
162	                'refund_rate' => $refundRate,
163	                'repeat_purchase_rate' => $repeatPurchaseRate,
164	                'group_conversion' => $groupConversion,
165	                'leader_performance' => $leaderStats,
166	                'product_popularity' => $productPopularity,
167	            ],
168	            'snapshots' => $snapshots,
169	            'metric_definitions' => $definitions,
170	        ];
171	    }
172	
173	    /**
174	     * Request an asynchronous data refresh for the given scope.
175	     * Rate limited to 5 requests per hour per user.
176	     *
177	     * @param int   $userId
178	     * @param array $scope  Refresh scope parameters (site_id).
179	     * @return array Refresh request record including request ID and status.
180	     */
181	    public function requestRefresh(int $userId, array $scope): array
182	    {
183	        $oneHourAgo = date('Y-m-d H:i:s', strtotime('-1 hour'));
184	        $recentCount = Db::table('analytics_refresh_requests')
185	            ->where('user_id', $userId)
186	            ->where('created_at', '>=', $oneHourAgo)
187	            ->count();
188	
189	        if ($recentCount >= 5) {
190	            throw new ValidateException('Rate limit exceeded. Maximum 5 refresh requests per hour.');
191	        }
192	
193	        $now = date('Y-m-d H:i:s');
194	        $id = Db::table('analytics_refresh_requests')->insertGetId([
195	            'user_id' => $userId,
196	            'site_id' => $scope['site_id'] ?? null,
197	            'status' => 'requested',
198	            'created_at' => $now,
199	        ]);
200	
201	        return [
202	            'id' => $id,
203	            'user_id' => $userId,
204	            'site_id' => $scope['site_id'] ?? null,
205	            'status' => 'requested',
206	            'created_at' => $now,
207	        ];
208	    }
209	
210	    /**
211	     * Get the status of a previously requested refresh.
212	     *
213	     * @param int $requestId
214	     * @return array|null Refresh status or null if not found.
215	     */
216	    public function getRefreshStatus(int $requestId): ?array
217	    {
218	        $record = Db::table('analytics_refresh_requests')
219	            ->where('id', $requestId)
220	            ->find();
221	
222	        return $record ?: null;
223	    }
224	}
