94	    /**
95	     * Queue a report run for the given definition.
96	     *
97	     * @param int $definitionId
98	     * @param int $userId
99	     * @return array The created run record with status 'queued'.
100	     */
101	    /**
102	     * @param int   $definitionId
103	     * @param int   $userId
104	     * @param array $siteScopes  Empty array means cross-site (privileged). Non-empty restricts to those site IDs.
105	     */
106	    public function queueRun(int $definitionId, int $userId, array $siteScopes = []): array
107	    {
108	        $definition = Db::table('report_definitions')->where('id', $definitionId)->find();
109	        if (!$definition) {
110	            throw new ValidateException('Report definition not found.');
111	        }
112	
113	        $now = date('Y-m-d H:i:s');
114	        $id = Db::table('report_runs')->insertGetId([
115	            'definition_id' => $definitionId,
116	            'status' => 'queued',
117	            'created_at' => $now,
118	        ]);
119	
120	        // Execute synchronously for the scaffold phase
121	        $this->executeRun($id, $siteScopes);
122	
123	        return Db::table('report_runs')->where('id', $id)->find();
124	    }
