126	    /**
127	     * Execute a report run: query data, generate CSV, create artifact record.
128	     *
129	     * @param int $runId
130	     * @return void
131	     */
132	    /**
133	     * @param int   $runId
134	     * @param array $siteScopes  Empty means cross-site (no restriction).
135	     */
136	    public function executeRun(int $runId, array $siteScopes = []): void
137	    {
138	        $run = Db::table('report_runs')->where('id', $runId)->find();
139	        if (!$run) {
140	            throw new ValidateException('Report run not found.');
141	        }
142	
143	        $definition = Db::table('report_definitions')->where('id', $run['definition_id'])->find();
144	        if (!$definition) {
145	            Db::table('report_runs')->where('id', $runId)->update([
146	                'status' => 'failed',
147	                'completed_at' => date('Y-m-d H:i:s'),
148	            ]);
149	            return;
150	        }
151	
152	        Db::table('report_runs')->where('id', $runId)->update([
153	            'status' => 'running',
154	            'started_at' => date('Y-m-d H:i:s'),
155	        ]);
156	
157	        try {
158	            $dimensions = !empty($definition['dimensions_json'])
159	                ? json_decode($definition['dimensions_json'], true) : [];
160	            $filters = !empty($definition['filters_json'])
161	                ? json_decode($definition['filters_json'], true) : [];
162	            $columns = !empty($definition['columns_json'])
163	                ? json_decode($definition['columns_json'], true) : [];
164	
165	            $reportType = $dimensions['type'] ?? ($filters['type'] ?? 'general');
166	
167	            $data = $this->queryReportData($reportType, $dimensions, $filters, $siteScopes);
168	
169	            $csvColumns = !empty($columns) ? $columns : (!empty($data) ? array_keys($data[0]) : []);
170	
171	            $filePath = $this->csvExportService->generateCsv($data, $csvColumns, []);
172	
173	            $now = date('Y-m-d H:i:s');
174	            $expiresAt = date('Y-m-d H:i:s', strtotime('+180 days'));
175	
176	            // report_artifacts schema: run_id, file_path, file_size, sha256_hash, created_at
177	            $fileSize = file_exists($filePath) ? filesize($filePath) : 0;
178	            $sha256 = file_exists($filePath) ? hash_file('sha256', $filePath) : '';
179	
180	            Db::table('report_artifacts')->insert([
181	                'run_id'      => $runId,
182	                'file_path'   => $filePath,
183	                'file_size'   => $fileSize,
184	                'sha256_hash' => $sha256,
185	                'created_at'  => $now,
186	            ]);
187	
188	            // report_runs schema: artifact_path, expires_at, started_at, completed_at
189	            Db::table('report_runs')->where('id', $runId)->update([
190	                'status'        => 'succeeded',
191	                'artifact_path' => $filePath,
192	                'expires_at'    => $expiresAt,
193	                'completed_at'  => $now,
194	            ]);
195	        } catch (\Throwable $e) {
196	            Db::table('report_runs')->where('id', $runId)->update([
197	                'status'       => 'failed',
198	                'completed_at' => date('Y-m-d H:i:s'),
199	            ]);
200	            throw $e;
201	        }
202	    }
203	
204	    /**
205	     * Query report data based on the report type and definition parameters.
206	     *
207	     * @param string $reportType
208	     * @param array  $dimensions
209	     * @param array  $filters
210	     * @return array
211	     */
212	    /**
213	     * @param string $reportType
214	     * @param array  $dimensions
215	     * @param array  $filters
216	     * @param array  $siteScopes  Non-empty enforces site_id restriction for non-privileged users.
217	     */
218	    private function queryReportData(string $reportType, array $dimensions, array $filters, array $siteScopes = []): array
219	    {
220	        $query = null;
221	
222	        switch ($reportType) {
223	            case 'participation':
224	                $query = Db::table('participants')
225	                    ->field('site_id, COUNT(*) as participant_count')
226	                    ->group('site_id');
227	                break;
228	
229	            case 'retention':
230	                $query = Db::table('participants')
231	                    ->alias('p')
232	                    ->leftJoin('orders o', 'o.participant_id = p.id')
233	                    ->field('p.id, p.name, COUNT(o.id) as order_count, IF(COUNT(o.id) > 1, "repeat", "one-time") as participant_type')
234	                    ->group('p.id, p.name');
235	                break;
236	
237	            case 'pass_rate':
238	                $query = Db::table('recipes')
239	                    ->field('status, COUNT(*) as recipe_count, ROUND(COUNT(CASE WHEN status = "approved" THEN 1 END) * 100.0 / COUNT(*), 2) as approval_rate')
240	                    ->group('status');
241	                break;
242	
243	            case 'regional_distribution':
244	                $query = Db::table('orders')
245	                    ->alias('o')
246	                    ->leftJoin('participants p', 'p.id = o.participant_id')
247	                    ->field('o.site_id, COUNT(DISTINCT o.id) as order_count, COUNT(DISTINCT o.participant_id) as participant_count')
248	                    ->group('o.site_id');
249	                break;
250	
251	            default:
252	                // General report: determine table from dimensions or default to orders
253	                $table = $dimensions['table'] ?? 'orders';
254	                $allowedTables = ['orders', 'participants', 'recipes', 'settlement_statements'];
255	                if (!in_array($table, $allowedTables, true)) {
256	                    $table = 'orders';
257	                }
258	                $query = Db::table($table);
259	                break;
260	        }
261	
262	        // Apply common filters
263	        if (!empty($filters['site_id'])) {
264	            $siteCol = in_array($reportType, ['retention']) ? 'p.site_id' : 'site_id';
265	            $query->where($siteCol, $filters['site_id']);
266	        }
267	        if (!empty($filters['site_ids']) && is_array($filters['site_ids'])) {
268	            $siteCol = in_array($reportType, ['retention']) ? 'p.site_id' : 'site_id';
269	            $query->whereIn($siteCol, $filters['site_ids']);
270	        }
271	        if (!empty($filters['date_from'])) {
272	            $dateCol = in_array($reportType, ['retention']) ? 'p.created_at' : 'created_at';
273	            $query->where($dateCol, '>=', $filters['date_from']);
274	        }
275	        if (!empty($filters['date_to'])) {
276	            $dateCol = in_array($reportType, ['retention']) ? 'p.created_at' : 'created_at';
277	            $query->where($dateCol, '<=', $filters['date_to']);
278	        }
279	        if (!empty($filters['status'])) {
280	            $query->where('status', $filters['status']);
281	        }
282	
283	        // Enforce site-scope restriction for non-privileged users
284	        if (!empty($siteScopes)) {
285	            $siteCol = in_array($reportType, ['retention']) ? 'p.site_id'
286	                : (in_array($reportType, ['regional_distribution']) ? 'o.site_id' : 'site_id');
287	            $query->whereIn($siteCol, $siteScopes);
288	        }
289	
290	        return $query->select()->toArray();
291	    }
292	
293	    /**
294	     * Get a report run by ID, including artifact info if available.
295	     *
296	     * @param int $id
297	     * @return array|null Run data or null if not found.
298	     */
299	    public function getRun(int $id): ?array
300	    {
301	        $run = Db::table('report_runs')->where('id', $id)->find();
302	        if (!$run) {
303	            return null;
304	        }
305	
306	        $artifact = Db::table('report_artifacts')->where('run_id', $id)->find();
307	        if ($artifact) {
308	            $run['artifact'] = $artifact;
309	        }
310	
311	        return $run;
312	    }
313	
314	    /**
315	     * List report runs, optionally filtered.
316	     *
317	     * @param array $filters Query filters (definition_id, status, page, per_page).
318	     * @return array Paginated list of run records.
319	     */
320	    public function listRuns(array $filters): array
321	    {
322	        $page = max(1, (int) ($filters['page'] ?? 1));
323	        $perPage = min(100, max(1, (int) ($filters['per_page'] ?? 20)));
324	
325	        $query = Db::table('report_runs')->alias('r');
326	
327	        // Ownership scoping: non-privileged users only see runs for their own definitions
328	        $userRoles = $filters['user_roles'] ?? [];
329	        $privilegedRoles = ['administrator', 'auditor'];
330	        if (!empty($filters['user_id']) && empty(array_intersect($userRoles, $privilegedRoles))) {
331	            $query->join('report_definitions d', 'r.definition_id = d.id')
332	                  ->where('d.created_by', $filters['user_id']);
333	        }
334	
335	        if (!empty($filters['definition_id'])) {
336	            $query->where('r.definition_id', $filters['definition_id']);
337	        }
338	        if (!empty($filters['status'])) {
339	            $query->where('r.status', $filters['status']);
340	        }
341	
342	        $total = (clone $query)->count();
343	
344	        $rows = $query->field('r.*')
345	            ->order('r.created_at', 'desc')
346	            ->limit(($page - 1) * $perPage, $perPage)
347	            ->select()
348	            ->toArray();
349	
350	        return [
351	            'data' => $rows,
352	            'total' => $total,
353	            'page' => $page,
354	            'per_page' => $perPage,
355	        ];
356	    }
357	
358	    /**
359	     * Schedule recurring execution of a report definition.
360	     *
361	     * @param int   $definitionId
362	     * @param array $schedule Schedule configuration (cadence, next_run_at, active).
363	     * @return void
364	     */
365	    public function scheduleReport(int $definitionId, array $schedule): void
366	    {
367	        $definition = Db::table('report_definitions')->where('id', $definitionId)->find();
368	        if (!$definition) {
369	            throw new ValidateException('Report definition not found.');
370	        }
371	
372	        $existing = Db::table('report_schedules')
373	            ->where('definition_id', $definitionId)
374	            ->find();
375	
376	        $now = date('Y-m-d H:i:s');
377	
378	        // Ensure next_run_at is set so the schedule is immediately runnable
379	        if (empty($schedule['next_run_at'])) {
380	            $schedule['next_run_at'] = $now;
381	        }
382	
383	        if ($existing) {
384	            $update = ['updated_at' => $now];
385	            if (isset($schedule['cadence'])) {
386	                $update['cadence'] = $schedule['cadence'];
387	            }
388	            if (isset($schedule['next_run_at'])) {
389	                $update['next_run_at'] = $schedule['next_run_at'];
390	            }
391	            if (isset($schedule['active'])) {
392	                $update['active'] = $schedule['active'] ? 1 : 0;
393	            }
394	            Db::table('report_schedules')->where('id', $existing['id'])->update($update);
395	        } else {
396	            Db::table('report_schedules')->insert([
397	                'definition_id' => $definitionId,
398	                'cadence' => $schedule['cadence'] ?? 'daily',
399	                'next_run_at' => $schedule['next_run_at'] ?? null,
400	                'active' => isset($schedule['active']) ? ($schedule['active'] ? 1 : 0) : 1,
401	                'created_at' => $now,
402	                'updated_at' => $now,
403	            ]);
404	        }
405	    }
406	}
