6	use think\facade\Db;
7	
8	class AuthService
9	{
10	    private PasswordHashService $passwordHash;
11	
12	    public function __construct(PasswordHashService $passwordHash)
13	    {
14	        $this->passwordHash = $passwordHash;
15	    }
16	
17	    /**
18	     * Authenticate a user by username and password.
19	     *
20	     * @return array|null User data on success, null on failure.
21	     */
22	    public function attempt(string $username, string $password): ?array
23	    {
24	        $user = Db::name('users')
25	            ->where('username', $username)
26	            ->where('status', 'active')
27	            ->find();
28	
29	        if (!$user) {
30	            return null;
31	        }
32	
33	        if (!$this->passwordHash->verify($password, $user['password_hash'])) {
34	            return null;
35	        }
36	
37	        // Rehash if algorithm/cost changed
38	        if ($this->passwordHash->needsRehash($user['password_hash'])) {
39	            Db::name('users')
40	                ->where('id', $user['id'])
41	                ->update(['password_hash' => $this->passwordHash->hash($password)]);
42	        }
43	
44	        return [
45	            'id'           => (int)$user['id'],
46	            'username'     => $user['username'],
47	            'display_name' => $user['display_name'],
48	        ];
49	    }
50	
51	    /**
52	     * Resolve roles and site scopes for a user.
53	     */
54	    public function resolveUserRolesAndScopes(int $userId): array
55	    {
56	        $roles = Db::name('user_roles')
57	            ->alias('ur')
58	            ->join('roles r', 'ur.role_id = r.id')
59	            ->where('ur.user_id', $userId)
60	            ->column('r.name');
61	
62	        $siteScopes = Db::name('user_site_scopes')
63	            ->where('user_id', $userId)
64	            ->column('site_id');
65	
66	        return [
67	            'roles'       => $roles,
68	            'site_scopes' => $siteScopes,
