declare(strict_types=1);

namespace tests\Feature\Reports;

use tests\TestCase;

/**
 * Tests that scheduled report runs enforce site-scope for non-privileged users.
 *
 * The ScheduledReportJob should resolve the definition owner's roles and
 * site scopes, passing them into executeRun so non-privileged owners
 * cannot produce cross-site data.
 */
class ScheduledReportScopeTest extends TestCase
{
    private array $analystSession;
    private array $adminSession;

    protected function setUp(): void
    {
        parent::setUp();
        $this->analystSession = $this->loginAs('analyst');
        $this->adminSession   = $this->loginAs('admin');
        $this->assertNotEmpty($this->analystSession['csrf_token'], 'Analyst login must succeed');
        $this->assertNotEmpty($this->adminSession['csrf_token'], 'Admin login must succeed');
    }

    /**
     * When a non-privileged user creates a definition and schedules it,
     * the schedule endpoint should succeed. The ScheduledReportJob
     * will resolve scope from the definition owner at execution time.
     */
    public function testNonPrivilegedScheduleCreatesSuccessfully(): void
    {
        // Create definition as analyst
        $createResponse = $this->authenticatedRequest('POST', '/api/v1/reports/definitions', $this->analystSession, [
            'name'        => 'Analyst Scheduled Report ' . uniqid(),
            'description' => 'Scheduled scope test',
            'dimensions'  => ['type' => 'participation'],
        ]);
        $this->assertEquals(201, $createResponse['status'],
            'Analyst should create definition. Got: ' . ($createResponse['raw'] ?? ''));
        $defId = $createResponse['body']['data']['id'] ?? null;
        $this->assertNotNull($defId);

        // Schedule as analyst
        $scheduleResponse = $this->authenticatedRequest('POST', "/api/v1/reports/definitions/{$defId}/schedule", $this->analystSession, [
            'cadence' => 'daily',
        ]);
        $this->assertEquals(201, $scheduleResponse['status'],
            'Analyst should schedule their own report. Got: ' . ($scheduleResponse['raw'] ?? ''));
    }

    /**
     * An interactive run by the analyst should enforce site scopes.
     * This verifies the pipeline the scheduled job also uses.
     */
    public function testAnalystInteractiveRunEnforcesSiteScope(): void
    {
        $createResponse = $this->authenticatedRequest('POST', '/api/v1/reports/definitions', $this->analystSession, [
            'name'        => 'Analyst Scope Run ' . uniqid(),
            'description' => 'Interactive scope test',
            'dimensions'  => ['type' => 'participation'],
        ]);
        $this->assertEquals(201, $createResponse['status']);
        $defId = $createResponse['body']['data']['id'] ?? null;
        $this->assertNotNull($defId);

        $runResponse = $this->authenticatedRequest('POST', "/api/v1/reports/definitions/{$defId}/run", $this->analystSession);
        $this->assertContains($runResponse['status'], [200, 202],
            'Analyst run should succeed. Got: ' . ($runResponse['raw'] ?? ''));

        $runId = $runResponse['body']['data']['run_id'] ?? null;
        $this->assertNotNull($runId);

        // Verify the run record exists and completed
        $runDetailResponse = $this->authenticatedRequest('GET', "/api/v1/reports/runs/{$runId}", $this->analystSession);
        $this->assertEquals(200, $runDetailResponse['status'],
            'Analyst should read their own run. Got: ' . ($runDetailResponse['raw'] ?? ''));
        $this->assertEquals('succeeded', $runDetailResponse['body']['data']['status'] ?? '',
            'Run should have succeeded');
    }

    /**
     * Admin-created scheduled definitions should not be site-restricted.
     */
    public function testAdminScheduleIsNotSiteRestricted(): void
    {
        $createResponse = $this->authenticatedRequest('POST', '/api/v1/reports/definitions', $this->adminSession, [
            'name'        => 'Admin Scheduled Report ' . uniqid(),
            'description' => 'Admin cross-site scheduled test',
            'dimensions'  => ['type' => 'participation'],
        ]);
        $this->assertEquals(201, $createResponse['status']);
        $defId = $createResponse['body']['data']['id'] ?? null;
        $this->assertNotNull($defId);

        // Run as admin (cross-site, no restriction)
        $runResponse = $this->authenticatedRequest('POST', "/api/v1/reports/definitions/{$defId}/run", $this->adminSession);
        $this->assertContains($runResponse['status'], [200, 202],
            'Admin run should succeed. Got: ' . ($runResponse['raw'] ?? ''));
    }
}
"}

