52	                            $siteScopes = $ownerContext['site_scopes'] ?? [];
53	                        }
54	                    }
55	
56	                    // Queue a report run for each due schedule
57	                    $runId = Db::name('report_runs')->insertGetId([
58	                        'definition_id' => $schedule['definition_id'],
59	                        'status'        => 'queued',
60	                        'created_at'    => date('Y-m-d H:i:s'),
61	                    ]);
62	
