3	namespace app\job;
4	
5	use think\console\Command;
6	use think\console\Input;
7	use think\console\Output;
8	use think\facade\Db;
9	use think\facade\Log;
10	use app\service\report\ReportService;
11	use app\service\auth\AuthService;
12	
13	class ScheduledReportJob extends Command
14	{
15	    protected function configure()
16	    {
17	        $this->setName('reports:scheduled')
18	            ->setDescription('Process scheduled report generation');
19	    }
20	
21	    protected function execute(Input $input, Output $output)
22	    {
23	        $output->writeln('[' . date('Y-m-d H:i:s') . '] Scheduled report processing started.');
24	        Log::info('Scheduled report processing started.');
25	
26	        try {
27	            // Query report schedules that are due for execution
28	            $dueSchedules = Db::name('report_schedules')
29	                ->where('active', true)
30	                ->where('next_run_at', '<=', date('Y-m-d H:i:s'))
31	                ->select();
32	
33	            $count = count($dueSchedules);
34	            $output->writeln("Found {$count} scheduled report(s) due for processing.");
35	            Log::info("Found {$count} scheduled report(s) due for processing.");
36	
37	            $reportService = app(ReportService::class);
38	            $authService = app(AuthService::class);
39	
40	            foreach ($dueSchedules as $schedule) {
41	                try {
42	                    // Resolve the definition owner's roles and site scopes
43	                    $definition = Db::name('report_definitions')
44	                        ->where('id', $schedule['definition_id'])
45	                        ->find();
46	
47	                    $siteScopes = [];
48	                    $isPrivileged = false;
49	
50	                    if ($definition) {
51	                        $ownerContext = $authService->resolveUserRolesAndScopes((int) $definition['created_by']);
52	                        $ownerRoles = $ownerContext['roles'] ?? [];
53	                        $crossSiteRoles = ['administrator', 'auditor'];
54	                        $isPrivileged = !empty(array_intersect($ownerRoles, $crossSiteRoles));
55	                        if (!$isPrivileged) {
56	                            $siteScopes = $ownerContext['site_scopes'] ?? [];
57	                        }
58	                    }
59	
60	                    // Queue a report run for each due schedule
61	                    $runId = Db::name('report_runs')->insertGetId([
62	                        'definition_id' => $schedule['definition_id'],
63	                        'status'        => 'queued',
64	                        'created_at'    => date('Y-m-d H:i:s'),
65	                    ]);
66	
67	                    // Non-privileged owners with empty scopes must not run cross-site
68	                    if (!$isPrivileged && empty($siteScopes)) {
69	                        $reason = 'Non-privileged definition owner has no site scopes assigned; cannot execute report.';
70	                        Db::name('report_runs')->where('id', $runId)->update([
71	                            'status'       => 'failed',
72	                            'completed_at' => date('Y-m-d H:i:s'),
73	                        ]);
74	                        $output->writeln("<error>Skipped report run #{$runId} for schedule #{$schedule['id']}: {$reason}</error>");
75	                        Log::warning("Skipped report run #{$runId} for schedule #{$schedule['id']}: {$reason}");
76	
77	                        // Still advance the schedule so it does not retry immediately
78	                    } else {
79	                        $output->writeln("Queued report run #{$runId} for schedule #{$schedule['id']} (definition #{$schedule['definition_id']}).");
80	                        Log::info("Queued report run #{$runId} for schedule #{$schedule['id']}.");
81	
82	                        // Execute the report run with owner's site scope context
83	                        $reportService->executeRun($runId, $siteScopes, $isPrivileged);
84	
85	                        $output->writeln("Executed report run #{$runId} for schedule #{$schedule['id']}.");
86	                        Log::info("Executed report run #{$runId} for schedule #{$schedule['id']}.");
87	                    }
88	
89	                    // Advance next_run_at based on cadence
90	                    $cadence = $schedule['cadence'] ?? 'daily';
91	                    $currentNextRun = $schedule['next_run_at'] ?? date('Y-m-d H:i:s');
92	                    switch ($cadence) {
93	                        case 'weekly':
94	                            $newNextRun = date('Y-m-d H:i:s', strtotime($currentNextRun . ' +7 days'));
95	                            break;
96	                        case 'monthly':
97	                            $newNextRun = date('Y-m-d H:i:s', strtotime($currentNextRun . ' +1 month'));
98	                            break;
99	                        case 'daily':
100	                        default:
101	                            $newNextRun = date('Y-m-d H:i:s', strtotime($currentNextRun . ' +1 day'));
102	                            break;
103	                    }
104	
105	                    Db::name('report_schedules')
106	                        ->where('id', $schedule['id'])
107	                        ->update([
108	                            'next_run_at' => $newNextRun,
109	                            'updated_at'  => date('Y-m-d H:i:s'),
110	                        ]);
111	
112	                    $output->writeln("Advanced schedule #{$schedule['id']} next_run_at to {$newNextRun}.");
113	                    Log::info("Advanced schedule #{$schedule['id']} next_run_at to {$newNextRun}.");
114	                } catch (\Exception $e) {
115	                    $output->writeln("<error>Failed to process report for schedule #{$schedule['id']}: {$e->getMessage()}</error>");
116	                    Log::error("Failed to process report for schedule #{$schedule['id']}: {$e->getMessage()}");
117	                }
118	            }
119	        } catch (\Exception $e) {
120	            $output->writeln('<error>Error processing scheduled reports: ' . $e->getMessage() . '</error>');
121	            Log::error('Error processing scheduled reports: ' . $e->getMessage(), [
122	                'trace' => $e->getTraceAsString(),
123	            ]);
124	        }
125	
126	        $output->writeln('[' . date('Y-m-d H:i:s') . '] Scheduled report processing completed.');
127	        Log::info('Scheduled report processing completed.');
128	    }
129	}
