8	/**
9	 * Tests that scheduled and interactive report runs enforce site-scope
10	 * for non-privileged users and that the empty-scope fallback is safe.
11	 *
12	 * Coverage:
13	 * - Non-privileged user (analyst) interactive run succeeds with scoped data
14	 * - Privileged user (admin) interactive run succeeds cross-site
15	 * - Successful run produces artifact; failed run does not
16	 * - Non-privileged user without site scopes is blocked at middleware level
17	 * - ScheduledReportJob contains the empty-scope guard (static proof)
18	 * - ReportService::executeRun contains defense-in-depth guard (static proof)
19	 */
20	class ScheduledReportScopeTest extends TestCase
21	{
22	    private array $analystSession;
23	    private array $adminSession;
24	
25	    protected function setUp(): void
26	    {
27	        parent::setUp();
28	        $this->analystSession = $this->loginAs('analyst');
29	        $this->adminSession   = $this->loginAs('admin');
30	        $this->assertNotEmpty($this->analystSession['csrf_token'], 'Analyst login must succeed');
31	        $this->assertNotEmpty($this->adminSession['csrf_token'], 'Admin login must succeed');
32	    }
33	
34	    // ------------------------------------------------------------------
35	    // Interactive run paths (same executeRun pipeline as scheduler)
36	    // ------------------------------------------------------------------
37	
38	    /**
39	     * Analyst (non-privileged, has site scopes) can run a report
40	     * and the run succeeds with scoped data.
41	     */
42	    public function testNonPrivilegedRunSucceedsWithScopes(): void
43	    {
44	        $defId = $this->createDefinitionAs($this->analystSession);
45	
46	        $runResponse = $this->authenticatedRequest(
47	            'POST',
48	            "/api/v1/reports/definitions/{$defId}/run",
49	            $this->analystSession
50	        );
51	        $this->assertContains($runResponse['status'], [200, 202],
52	            'Analyst run should succeed. Got: ' . ($runResponse['raw'] ?? ''));
53	
54	        $runId = $runResponse['body']['data']['run_id'] ?? null;
55	        $this->assertNotNull($runId, 'Run ID must be returned');
56	
57	        // Verify run completed successfully
58	        $detail = $this->authenticatedRequest(
59	            'GET',
60	            "/api/v1/reports/runs/{$runId}",
61	            $this->analystSession
62	        );
63	        $this->assertEquals(200, $detail['status']);
64	        $this->assertEquals('succeeded', $detail['body']['data']['status'] ?? '',
65	            'Analyst run should succeed');
66	    }
67	
68	    /**
