129	    // Empty-scope enforcement: middleware blocks non-privileged users
130	    // ------------------------------------------------------------------
131	
132	    /**
133	     * A non-privileged user with no site scopes cannot access any
134	     * authenticated endpoint (SiteScopeMiddleware returns 403).
135	     * This proves the interactive path is safe from empty-scope runs.
136	     */
137	    public function testScopelessNonPrivilegedUserIsBlockedByMiddleware(): void
138	    {
139	        $password = bootstrap_config('seed_admin_password', '');
140	        $username = 'scopeless_analyst_' . uniqid();
141	
142	        // Create a test user via admin API
143	        $createUser = $this->authenticatedRequest(
144	            'POST',
145	            '/api/v1/admin/users',
146	            $this->adminSession,
147	            [
148	                'username'     => $username,
149	                'password'     => $password,
150	                'display_name' => 'Scopeless Analyst',
151	            ]
152	        );
153	        $this->assertEquals(201, $createUser['status'],
154	            'Admin must create user. Got: ' . ($createUser['raw'] ?? ''));
155	        $userId = $createUser['body']['data']['id'] ?? null;
156	        $this->assertNotNull($userId);
157	
158	        // Find the operations_analyst role ID
159	        $rolesResponse = $this->authenticatedRequest(
160	            'GET',
161	            '/api/v1/rbac/roles',
162	            $this->adminSession
163	        );
164	        $this->assertEquals(200, $rolesResponse['status']);
165	        $roles = $rolesResponse['body']['data']['roles']
166	            ?? $rolesResponse['body']['data']['items']
167	            ?? $rolesResponse['body']['data']
168	            ?? [];
169	
170	        $analystRoleId = null;
171	        foreach ($roles as $role) {
172	            if (($role['name'] ?? '') === 'operations_analyst') {
173	                $analystRoleId = (int) $role['id'];
174	                break;
175	            }
176	        }
177	        $this->assertNotNull($analystRoleId,
178	            'operations_analyst role must exist in DB');
179	
180	        // Assign role but NO site scopes
181	        $assignRole = $this->authenticatedRequest(
182	            'POST',
183	            "/api/v1/admin/users/{$userId}/roles",
184	            $this->adminSession,
185	            ['role_ids' => [$analystRoleId]]
186	        );
187	        $this->assertEquals(200, $assignRole['status'],
188	            'Role assignment must succeed. Got: ' . ($assignRole['raw'] ?? ''));
189	
190	        // Explicitly assign empty site scopes
191	        $assignScopes = $this->authenticatedRequest(
192	            'POST',
193	            "/api/v1/admin/users/{$userId}/site-scopes",
194	            $this->adminSession,
195	            ['site_ids' => []]
196	        );
197	        $this->assertEquals(200, $assignScopes['status'],
198	            'Scope assignment must succeed. Got: ' . ($assignScopes['raw'] ?? ''));
199	
200	        // Attempt to log in as the scopeless user
201	        $scopelessSession = $this->loginAs($username);
202	
203	        // The user may get a CSRF token from login, but any subsequent
204	        // request should fail at SiteScopeMiddleware with 403
205	        $testResponse = $this->authenticatedRequest(
206	            'GET',
207	            '/api/v1/reports/definitions',
208	            $scopelessSession
209	        );
210	
211	        $this->assertEquals(403, $testResponse['status'],
212	            'Scopeless non-privileged user should be blocked by SiteScopeMiddleware (403). '
213	            . 'Got: ' . ($testResponse['raw'] ?? ''));
214	    }
