217	    // Scheduled path: empty-scope owner => run fails, no artifact
218	    // ------------------------------------------------------------------
219	
220	    /**
221	     * A report definition owned by a non-privileged user with zero site
222	     * scopes must produce a FAILED run with no artifact when the
223	     * scheduler processes it.
224	     *
225	     * Setup:
226	     *   1. Admin creates a user with operations_analyst role, empty scopes
227	     *   2. Insert a report_definitions row owned by that user (via DB)
228	     *   3. Insert a report_schedules row due now
229	     *   4. Invoke `php think reports:scheduled`
230	     *
231	     * Assertions:
232	     *   - A report_runs row exists for that definition
233	     *   - run status = 'failed'
234	     *   - artifact_path is null/empty
235	     *   - No report_artifacts row for that run
236	     */
237	    public function testScheduledRunFailsForNonPrivilegedOwnerWithEmptyScopesAndNoArtifact(): void
238	    {
239	        $password = bootstrap_config('seed_admin_password', '');
240	        $username = 'sched_scopeless_' . uniqid();
241	
242	        // --- 1. Create a scopeless analyst user via admin API ----------
243	        $createUser = $this->authenticatedRequest(
244	            'POST', '/api/v1/admin/users', $this->adminSession,
245	            ['username' => $username, 'password' => $password, 'display_name' => 'Sched Scopeless']
246	        );
247	        $this->assertEquals(201, $createUser['status'],
248	            'Admin must create user. Got: ' . ($createUser['raw'] ?? ''));
249	        $userId = (int) $createUser['body']['data']['id'];
250	
251	        // Find operations_analyst role ID
252	        $rolesResp = $this->authenticatedRequest('GET', '/api/v1/rbac/roles', $this->adminSession);
253	        $this->assertEquals(200, $rolesResp['status']);
254	        $roles = $rolesResp['body']['data']['roles']
255	            ?? $rolesResp['body']['data']['items']
256	            ?? $rolesResp['body']['data'] ?? [];
257	        $analystRoleId = null;
258	        foreach ($roles as $r) {
259	            if (($r['name'] ?? '') === 'operations_analyst') {
260	                $analystRoleId = (int) $r['id'];
261	                break;
262	            }
263	        }
264	        $this->assertNotNull($analystRoleId, 'operations_analyst role must exist');
265	
266	        // Assign role, empty site scopes
267	        $this->authenticatedRequest('POST', "/api/v1/admin/users/{$userId}/roles",
268	            $this->adminSession, ['role_ids' => [$analystRoleId]]);
269	        $this->authenticatedRequest('POST', "/api/v1/admin/users/{$userId}/site-scopes",
270	            $this->adminSession, ['site_ids' => []]);
271	
272	        // --- 2. Insert a report definition owned by that user ---------
273	        $defName = 'sched_scope_test_' . uniqid();
274	        $insertDef = "cd /app && php -r \""
275	            . "require 'vendor/autoload.php'; "
276	            . "(new think\\\\App())->initialize(); "
277	            . "\\$id = think\\\\facade\\\\Db::name('report_definitions')->insertGetId(["
278	            .   "'name'=>'{$defName}',"
279	            .   "'description'=>'scope test',"
280	            .   "'dimensions_json'=>'{\\\"type\\\":\\\"participation\\\"}',"
281	            .   "'created_by'=>{$userId},"
282	            .   "'created_at'=>date('Y-m-d H:i:s'),"
283	            .   "'updated_at'=>date('Y-m-d H:i:s')"
284	            . "]); "
285	            . "echo \\$id;"
286	            . "\"";
287	        exec($insertDef . ' 2>&1', $defOut, $defExit);
288	        $this->assertEquals(0, $defExit, 'Insert definition failed: ' . implode("\n", $defOut));
289	        $defId = (int) trim(end($defOut));
290	        $this->assertGreaterThan(0, $defId, 'Definition ID must be positive');
291	
292	        // --- 3. Insert a schedule row due now -------------------------
293	        $insertSched = "cd /app && php -r \""
294	            . "require 'vendor/autoload.php'; "
295	            . "(new think\\\\App())->initialize(); "
296	            . "think\\\\facade\\\\Db::name('report_schedules')->insert(["
297	            .   "'definition_id'=>{$defId},"
298	            .   "'cadence'=>'daily',"
299	            .   "'next_run_at'=>date('Y-m-d H:i:s', strtotime('-1 minute')),"
300	            .   "'active'=>1,"
301	            .   "'created_at'=>date('Y-m-d H:i:s'),"
302	            .   "'updated_at'=>date('Y-m-d H:i:s')"
303	            . "]);"
304	            . "\"";
305	        exec($insertSched . ' 2>&1', $schedOut, $schedExit);
306	        $this->assertEquals(0, $schedExit, 'Insert schedule failed: ' . implode("\n", $schedOut));
307	
308	        // --- 4. Run the scheduler -------------------------------------
309	        exec('cd /app && php think reports:scheduled 2>&1', $cmdOut, $cmdExit);
310	        $cmdText = implode("\n", $cmdOut);
311	        $this->assertEquals(0, $cmdExit, 'Scheduler command must exit 0. Output: ' . $cmdText);
312	
313	        // --- 5. Query the run row and artifact row --------------------
314	        $queryRun = "cd /app && php -r \""
315	            . "require 'vendor/autoload.php'; "
316	            . "(new think\\\\App())->initialize(); "
317	            . "\\$run = think\\\\facade\\\\Db::name('report_runs')"
318	            .   "->where('definition_id', {$defId})"
319	            .   "->order('id', 'desc')->find(); "
320	            . "echo json_encode(\\$run);"
321	            . "\"";
322	        exec($queryRun . ' 2>&1', $runOut, $runExit);
323	        $this->assertEquals(0, $runExit, 'Query run failed: ' . implode("\n", $runOut));
324	        $runRow = json_decode(trim(end($runOut)), true);
325	
326	        $this->assertNotEmpty($runRow, 'A report_runs row must exist for the definition');
327	        $runId = (int) $runRow['id'];
328	
329	        // Assert: run status is failed
330	        $this->assertEquals('failed', $runRow['status'],
331	            "Run status must be 'failed' for non-privileged owner with empty scopes. Got: " . ($runRow['status'] ?? 'null'));
332	
333	        // Assert: artifact_path is null or empty
334	        $this->assertEmpty($runRow['artifact_path'] ?? '',
335	            'Failed run must not have an artifact_path. Got: ' . ($runRow['artifact_path'] ?? ''));
336	
337	        // Assert: no report_artifacts row
338	        $queryArtifact = "cd /app && php -r \""
339	            . "require 'vendor/autoload.php'; "
340	            . "(new think\\\\App())->initialize(); "
341	            . "\\$count = think\\\\facade\\\\Db::name('report_artifacts')"
342	            .   "->where('run_id', {$runId})->count(); "
343	            . "echo \\$count;"
344	            . "\"";
345	        exec($queryArtifact . ' 2>&1', $artOut, $artExit);
346	        $this->assertEquals(0, $artExit, 'Query artifacts failed: ' . implode("\n", $artOut));
347	        $artifactCount = (int) trim(end($artOut));
348	        $this->assertEquals(0, $artifactCount,
349	            'No report_artifacts row must exist for a failed empty-scope run');
350	    }
